#!/usr/bin/env python3
import os, zlib, binascii, re
from pathlib import Path

GITDIR = Path('/home/ctfplayer/ctf_files/sourcery_extracted/.git')
OBJDIR = GITDIR/'objects'

objs = {}

for d in OBJDIR.iterdir():
    if not d.is_dir():
        continue
    if len(d.name)!=2 or any(c not in '0123456789abcdef' for c in d.name):
        continue
    for f in d.iterdir():
        if not f.is_file():
            continue
        oid = d.name + f.name
        raw = f.read_bytes()
        try:
            dec = zlib.decompress(raw)
        except Exception:
            continue
        nul = dec.find(b'\x00')
        hdr = dec[:nul].decode('utf-8','replace')
        typ, size = hdr.split(' ',1)
        payload = dec[nul+1:]
        objs[oid] = {'type':typ,'size':int(size),'payload':payload}

print(f'[+] recovered {len(objs)} loose objects')

commits = {}
for oid,o in objs.items():
    if o['type']!='commit':
        continue
    txt = o['payload'].decode('utf-8','replace')
    lines = txt.splitlines()
    tree = None
    parents = []
    author = ''
    committer = ''
    i = 0
    for i,l in enumerate(lines):
        if l == '':
            break
        if l.startswith('tree '): tree=l[5:]
        elif l.startswith('parent '): parents.append(l[7:])
        elif l.startswith('author '): author=l
        elif l.startswith('committer '): committer=l
    msg='\n'.join(lines[i+1:])
    commits[oid] = {'tree':tree,'parents':parents,'author':author,'committer':committer,'message':msg}

print('\n=== COMMITS ===')
for oid,c in commits.items():
    print(f'commit {oid}')
    print(f' tree {c["tree"]}')
    for p in c['parents']: print(f' parent {p}')
    print(f' {c["author"]}')
    print(f' {c["committer"]}')
    print(' message:')
    print(c['message'])
    print('---')

def parse_tree(tree_oid, base=''):
    o=objs.get(tree_oid)
    if not o or o['type']!='tree':
        return []
    data=o['payload']
    i=0
    out=[]
    while i<len(data):
        j=data.find(b' ',i)
        mode=data[i:j].decode()
        k=data.find(b'\x00',j+1)
        name=data[j+1:k].decode('utf-8','replace')
        sha=data[k+1:k+21].hex()
        i=k+21
        path=f'{base}/{name}' if base else name
        typ=objs.get(sha,{}).get('type','missing')
        out.append((mode,path,sha,typ))
        if typ=='tree':
            out.extend(parse_tree(sha,path))
    return out

# refs
refs={}
for rf in (GITDIR/'refs'/'heads').glob('*'):
    refs[rf.name]=rf.read_text().strip()

print('\n=== BRANCH TIPS ===')
for b,h in refs.items():
    print(f'{b}: {h}')

print('\n=== FILE TREES PER BRANCH TIP COMMIT ===')
for b,h in refs.items():
    if h not in commits:
        continue
    print(f'\n[{b} @ {h}]')
    entries=parse_tree(commits[h]['tree'])
    for mode,path,sha,typ in entries:
        if typ!='tree':
            print(f'{mode} {path} {sha} ({typ})')

print('\n=== BLOBS CONTENT PREVIEW + KEYWORD HITS ===')
keywords=[b'flag{',b'ctf',b'secret',b'token',b'password',b'api',b'key']
for oid,o in objs.items():
    if o['type']!='blob':
        continue
    p=o['payload']
    printable=sum((32<=c<127 or c in (9,10,13)) for c in p)
    is_text=(len(p)==0) or printable/len(p) > 0.90
    print(f'blob {oid} size={len(p)} text={is_text}')
    if is_text:
        txt=p.decode('utf-8','replace')
        print(txt[:400])
        low=txt.lower()
        for kw in keywords:
            if kw.decode() in low:
                print(f'  [*] keyword hit: {kw.decode()}')
    else:
        print(binascii.hexlify(p[:64]).decode())
    print('---')

# exhaustive search in commit messages + blob text
print('\n=== GLOBAL CANDIDATE SEARCH ===')
pat=re.compile(r'flag\{[^}]*\}',re.I)
for oid,c in commits.items():
    for m in pat.findall(c['message']):
        print(f'commit {oid}: {m}')
for oid,o in objs.items():
    if o['type']!='blob':
        continue
    try: txt=o['payload'].decode('utf-8','ignore')
    except: continue
    for m in pat.findall(txt):
        print(f'blob {oid}: {m}')

